const DESCRIPTIONS: Record<string, string> = {
  // Mag 7
  'AAPL': 'Apple designs and manufactures consumer electronics including iPhone, Mac, iPad, and Apple Watch, along with services like the App Store, Apple Music, and iCloud. It is one of the most valuable companies in the world, known for its vertically integrated hardware-software ecosystem and strong brand loyalty.',
  'MSFT': 'Microsoft develops software, cloud computing, and enterprise solutions including Windows, Office 365, Azure, and LinkedIn. The company is a dominant force in enterprise software and cloud infrastructure, and a leading investor in artificial intelligence through its partnership with OpenAI.',
  'GOOGL': 'Alphabet is the parent company of Google, operating the world\'s largest search engine, YouTube, and the Google Cloud Platform. The company generates the majority of its revenue from digital advertising and holds commanding market share in search, mobile operating systems via Android, and online video.',
  'AMZN': 'Amazon is the world\'s largest e-commerce company and a leading cloud computing provider through Amazon Web Services (AWS). The company also operates in digital advertising, streaming media via Prime Video, and grocery retail through Whole Foods.',
  'NVDA': 'NVIDIA designs graphics processing units (GPUs) and system-on-chip units for gaming, professional visualization, data centers, and automotive markets. The company has become the dominant supplier of AI training and inference chips, making it central to the artificial intelligence infrastructure buildout.',
  'META': 'Meta Platforms operates Facebook, Instagram, WhatsApp, and Messenger, serving billions of users worldwide. The company is one of the largest digital advertising businesses globally and is investing heavily in augmented and virtual reality through its Reality Labs division.',
  'TSLA': 'Tesla designs, manufactures, and sells electric vehicles including the Model 3, Model Y, Model S, and Model X, along with energy storage and solar products. The company is the world\'s most valuable automaker and a pioneer in battery technology, autonomous driving software, and direct-to-consumer vehicle sales.',

  // Top Tech
  'CRM': 'Salesforce is the world\'s leading customer relationship management (CRM) platform, providing cloud-based software for sales, service, marketing, and analytics. The company has expanded through acquisitions including Slack, Tableau, and MuleSoft to become a comprehensive enterprise software provider.',
  'ADBE': 'Adobe develops creative, document, and digital marketing software including Photoshop, Illustrator, Premiere Pro, and Acrobat. The company pioneered the transition to cloud-based subscription software with Creative Cloud and holds a dominant position in creative professional tools.',
  'ORCL': 'Oracle provides enterprise database software, cloud infrastructure, and business applications for companies worldwide. The company is one of the largest enterprise software vendors and has been aggressively expanding its cloud infrastructure business to compete with AWS, Azure, and Google Cloud.',
  'INTC': 'Intel designs and manufactures semiconductor chips for personal computers, data centers, and embedded systems. Once the dominant chipmaker globally, the company is investing heavily in new fabrication facilities to regain manufacturing leadership and compete in the AI chip market.',
  'AMD': 'Advanced Micro Devices designs high-performance CPUs, GPUs, and adaptive computing processors for data centers, gaming, and embedded systems. The company has gained significant market share from Intel in server and PC processors and is expanding its AI accelerator portfolio.',
  'QCOM': 'Qualcomm designs and licenses wireless technology and manufactures semiconductor chips for mobile devices, automotive, and IoT applications. The company\'s Snapdragon processors power the majority of Android smartphones worldwide, and it holds essential patents for 3G, 4G, and 5G cellular technology.',
  'AVGO': 'Broadcom designs semiconductor and infrastructure software solutions for data centers, networking, broadband, and wireless communications. The company is a major supplier of networking chips, custom AI accelerators, and enterprise software following its acquisition of VMware.',
  'IBM': 'IBM provides hybrid cloud computing, artificial intelligence, and consulting services to enterprise customers worldwide. The company has pivoted from legacy hardware and services toward cloud and AI solutions, anchored by its Red Hat acquisition and watsonx AI platform.',
  'CSCO': 'Cisco Systems is the world\'s largest networking equipment company, manufacturing routers, switches, and security appliances for enterprise and service provider networks. The company is expanding into software-defined networking, cybersecurity, and collaboration tools as networks become increasingly software-driven.',
  'NOW': 'ServiceNow provides cloud-based workflow automation and IT service management software for enterprises. The company\'s platform is widely used for IT operations, employee experience, customer service, and security workflows, with strong revenue growth and high customer retention rates.',
  'SHOP': 'Shopify provides e-commerce platform software that enables merchants of all sizes to set up online stores, process payments, and manage operations. The company powers millions of businesses worldwide and has expanded into point-of-sale, fulfillment, and financial services for merchants.',
  'PLTR': 'Palantir Technologies builds data analytics and artificial intelligence software platforms for government and commercial customers. The company\'s Gotham and Foundry platforms are used for defense, intelligence, and enterprise data integration, and its AIP platform is driving adoption of large language models in operations.',
  'ARM': 'Arm Holdings designs and licenses semiconductor intellectual property, particularly CPU architectures used in virtually all smartphones and an increasing share of data center and automotive chips. The company operates a royalty-based business model, earning fees on billions of chips shipped annually by its licensees.',
  'SNOW': 'Snowflake provides a cloud-based data warehousing and analytics platform that runs on AWS, Azure, and Google Cloud. The company enables organizations to store, share, and analyze large volumes of data with a consumption-based pricing model.',
  'UBER': 'Uber Technologies operates ride-hailing, food delivery (Uber Eats), and freight logistics platforms across dozens of countries. The company is the largest ride-sharing platform globally and has become a major player in on-demand food delivery.',
  'SQ': 'Block (formerly Square) provides payment processing, financial services, and point-of-sale solutions for businesses of all sizes. The company also operates Cash App, a popular consumer finance platform for peer-to-peer payments, banking, and cryptocurrency trading.',
  'PYPL': 'PayPal operates a digital payments platform that enables online and mobile payments for consumers and merchants worldwide. The company processes hundreds of billions in payment volume annually through its PayPal, Venmo, and Braintree services.',
  'COIN': 'Coinbase operates the largest cryptocurrency exchange in the United States, providing a platform for buying, selling, and storing digital assets. The company also offers institutional custody, staking, and blockchain infrastructure services.',
  'NET': 'Cloudflare provides content delivery, cybersecurity, and edge computing services that protect and accelerate internet applications. The company operates one of the world\'s largest networks spanning hundreds of cities and serves millions of websites and applications.',
  'NFLX': 'Netflix is the world\'s largest streaming entertainment service with hundreds of millions of subscribers across 190+ countries. The company produces and distributes a wide range of original films, series, documentaries, and games, and has pioneered the shift from linear television to on-demand streaming.',
  'SPOT': 'Spotify is the world\'s largest audio streaming platform, offering music, podcasts, and audiobooks to hundreds of millions of users. The company operates a freemium model with both ad-supported and premium subscription tiers across nearly all global markets.',
  'SNAP': 'Snap operates Snapchat, a visual messaging and social media platform primarily popular with younger demographics. The company generates revenue through advertising and has invested in augmented reality technology, including AR glasses and camera-based experiences.',
  'PINS': 'Pinterest operates a visual discovery and bookmarking platform where users find inspiration for products, recipes, fashion, home design, and more. The company monetizes through advertising, positioning itself as a shopping-oriented platform that connects users with purchasable products.',
  'RDDT': 'Reddit operates one of the largest online community platforms, hosting millions of discussion forums (subreddits) on virtually every topic. The company generates revenue from advertising and data licensing, and its content is widely used to train AI models.',
  'RBLX': 'Roblox operates an online platform where users create, share, and play games and virtual experiences built by its community of developers. The platform is particularly popular among younger users and has expanded into social features, concerts, brand experiences, and virtual commerce.',
  'DDOG': 'Datadog provides cloud-based monitoring, security, and analytics tools for developers and IT operations teams. The company\'s platform unifies metrics, traces, and logs to provide observability across cloud applications, making it a leading vendor in the fast-growing cloud monitoring market.',
  'CRWD': 'CrowdStrike provides cloud-native endpoint security and threat intelligence through its Falcon platform. The company is a leader in endpoint detection and response (EDR) and has expanded into identity protection, cloud security, and log management.',
  'PANW': 'Palo Alto Networks is the world\'s largest cybersecurity company by revenue, providing next-generation firewalls, cloud security, and security operations solutions. The company has transitioned to a platform-based approach, consolidating multiple security functions into integrated offerings.',
  'ZS': 'Zscaler provides cloud-based cybersecurity services, including secure web gateways, zero-trust network access, and data protection. The company\'s Zero Trust Exchange platform routes and inspects enterprise traffic in the cloud, replacing traditional on-premises security appliances.',
  'FTNT': 'Fortinet provides cybersecurity solutions including firewalls, endpoint protection, and network security appliances for enterprises and service providers. The company is known for its FortiGate firewall platform and custom-built security processing units that deliver high-performance network protection.',

  // Finance
  'JPM': 'JPMorgan Chase is the largest bank in the United States by assets, providing investment banking, commercial banking, asset management, and consumer financial services. The company is a dominant player in global trading, M&A advisory, and credit card issuance.',
  'BAC': 'Bank of America is one of the largest financial institutions in the United States, serving individual consumers, small businesses, and large corporations with banking, lending, and investment services. The company operates one of the largest branch networks in the country and is a major player in wealth management through Merrill Lynch.',
  'WFC': 'Wells Fargo is a major U.S. bank providing consumer banking, commercial banking, corporate and investment banking, and wealth management services. The company operates one of the largest branch and ATM networks in the United States.',
  'GS': 'Goldman Sachs is a global investment bank and financial services company specializing in investment banking, securities trading, asset management, and consumer banking. The firm is one of the most prestigious names on Wall Street and a leading advisor on mergers, acquisitions, and IPOs.',
  'MS': 'Morgan Stanley is a global financial services firm providing investment banking, securities trading, wealth management, and investment management services. The company is one of the largest wealth managers in the world following its acquisition of E*TRADE and Eaton Vance.',
  'C': 'Citigroup is a global banking and financial services company operating in over 160 countries, providing consumer banking, institutional banking, and markets and securities services. The company has one of the most extensive international banking networks among U.S. banks.',
  'V': 'Visa operates the world\'s largest electronic payment network, processing trillions of dollars in transactions annually across more than 200 countries. The company connects consumers, merchants, financial institutions, and governments through its payment technology infrastructure.',
  'MA': 'Mastercard operates a global payments technology network connecting consumers, financial institutions, merchants, and governments. The company processes billions of transactions annually and is expanding into areas like open banking, digital identity, and real-time payments.',
  'AXP': 'American Express operates a global payments network and issues charge and credit cards, primarily targeting affluent consumers and businesses. The company differentiates through premium rewards, travel benefits, and its closed-loop network where it serves as both card issuer and payment processor.',
  'BLK': 'BlackRock is the world\'s largest asset management firm, overseeing trillions of dollars in assets through its mutual funds, exchange-traded funds (including the iShares brand), and institutional investment strategies. The company\'s Aladdin technology platform is also widely used for risk management and portfolio analytics.',
  'SCHW': 'Charles Schwab is one of the largest brokerage and banking firms in the United States, providing investment services, trading, and wealth management to individual investors and independent financial advisors. The company acquired TD Ameritrade, significantly expanding its client base and assets under management.',
  'BRK-B': 'Berkshire Hathaway is a multinational conglomerate led by Warren Buffett, holding a diverse portfolio of wholly owned businesses including GEICO, BNSF Railway, and Berkshire Hathaway Energy, alongside major public equity investments. The company is one of the most valuable in the world and is known for its long-term value investing approach.',
  'CME': 'CME Group operates the world\'s largest derivatives marketplace, offering trading in futures and options on interest rates, equity indexes, foreign exchange, energy, agricultural commodities, and metals. The company owns and operates the Chicago Mercantile Exchange, Chicago Board of Trade, New York Mercantile Exchange, and COMEX.',
  'ICE': 'Intercontinental Exchange operates global exchanges, clearing houses, and data services for financial and commodity markets. The company owns the New York Stock Exchange and provides mortgage technology services through its acquisition of Black Knight.',
  'SPGI': 'S&P Global provides financial data, credit ratings, benchmarks, and analytics to capital and commodity markets worldwide. The company operates the S&P ratings agency, the S&P Dow Jones Indices business, and market intelligence and commodity insights divisions following its merger with IHS Markit.',

  // Healthcare
  'JNJ': 'Johnson & Johnson is a global healthcare company operating in pharmaceuticals and medical devices after spinning off its consumer health division as Kenvue. The company\'s pharmaceutical segment focuses on immunology, oncology, and neuroscience, while its MedTech division produces surgical instruments, orthopedic products, and vision care.',
  'UNH': 'UnitedHealth Group is the largest health insurance company in the United States, providing managed care services through UnitedHealthcare and health services, analytics, and technology through Optum. The company serves tens of millions of members and is a dominant force in U.S. healthcare.',
  'PFE': 'Pfizer is a global pharmaceutical company that discovers, develops, and manufactures medicines and vaccines across multiple therapeutic areas including oncology, immunology, and rare diseases. The company gained worldwide recognition for co-developing one of the first COVID-19 mRNA vaccines with BioNTech.',
  'MRK': 'Merck is a global pharmaceutical company known for blockbuster drugs including Keytruda, one of the world\'s best-selling cancer immunotherapy treatments. The company also has strong franchises in vaccines, including Gardasil, and animal health products through its Merck Animal Health division.',
  'LLY': 'Eli Lilly is a global pharmaceutical company that has become one of the most valuable healthcare companies in the world, driven by its diabetes and obesity treatments including Mounjaro and Zepbound. The company also has a strong pipeline in neuroscience, oncology, and immunology.',
  'ABBV': 'AbbVie is a biopharmaceutical company focused on immunology, oncology, neuroscience, and eye care. The company\'s portfolio includes Humira (formerly the world\'s best-selling drug), Skyrizi, and Rinvoq, and it expanded into aesthetics and neuroscience through its acquisition of Allergan.',
  'TMO': 'Thermo Fisher Scientific is the world\'s largest life sciences tools and diagnostics company, providing analytical instruments, reagents, consumables, software, and services for pharmaceutical, biotech, and academic research. The company plays a critical role in drug discovery, clinical trials, and laboratory operations.',
  'ABT': 'Abbott Laboratories is a global healthcare company producing medical devices, diagnostics, nutritional products, and branded generic pharmaceuticals. The company\'s products include the FreeStyle Libre continuous glucose monitor, infant nutrition brands like Similac, and rapid diagnostic tests.',
  'MDT': 'Medtronic is the world\'s largest medical device company, producing therapeutic and diagnostic equipment for cardiovascular, neuroscience, medical-surgical, and diabetes care. The company\'s products include pacemakers, insulin pumps, surgical robotics systems, and spinal implants.',
  'AMGN': 'Amgen is one of the world\'s largest biotechnology companies, developing and manufacturing treatments for serious illnesses including cardiovascular disease, oncology, bone health, and inflammation. Key products include Enbrel, Prolia, Repatha, and biosimilars.',
  'GILD': 'Gilead Sciences is a biopharmaceutical company best known for its antiviral medications, including curative hepatitis C treatments and the HIV prevention drug Truvada. The company has expanded into oncology through its acquisition of Kite Pharma and its CAR-T cell therapy platform.',
  'MRNA': 'Moderna is a biotechnology company pioneering messenger RNA (mRNA) therapeutics and vaccines. The company gained global prominence with its COVID-19 vaccine and is developing mRNA-based treatments and vaccines for respiratory viruses, cancer, rare diseases, and autoimmune conditions.',
  'NVO': 'Novo Nordisk is a Danish pharmaceutical company and the world\'s largest producer of insulin and GLP-1 receptor agonist therapies for diabetes and obesity. The company\'s Ozempic and Wegovy have made it one of the most valuable companies in Europe as demand for weight-loss medications surges globally.',
  'ISRG': 'Intuitive Surgical is the global leader in robotic-assisted minimally invasive surgery, known for its da Vinci surgical systems used in urology, gynecology, and general surgery. The company has an installed base of thousands of systems worldwide and generates substantial recurring revenue from instruments and accessories.',
  'BMY': 'Bristol-Myers Squibb is a global pharmaceutical company with leading positions in oncology, hematology, cardiovascular, and immunology. Key products include Eliquis, Opdivo, and Revlimid, and the company has been actively building its pipeline through acquisitions.',
  'REGN': 'Regeneron Pharmaceuticals is a biotechnology company that discovers, develops, and commercializes medicines for eye diseases, allergic and inflammatory conditions, cancer, and infectious diseases. Its top-selling product Eylea treats retinal diseases, and the company is known for its proprietary antibody technology platform.',
  'VRTX': 'Vertex Pharmaceuticals is a biotechnology company that dominates the cystic fibrosis treatment market with its portfolio of CF medicines including Trikafta. The company is expanding into pain management, kidney disease, and gene editing therapies.',
  'DHR': 'Danaher is a global science and technology company providing life sciences, diagnostics, and environmental and applied solutions. The company owns well-known brands including Beckman Coulter, Leica Microsystems, and Pall, and is known for applying the Danaher Business System to drive operational improvement.',
  'SYK': 'Stryker is a medical technology company specializing in orthopedic implants, surgical equipment, neurotechnology, and spine products. The company is one of the largest medical device makers globally, known for its joint replacement systems and Mako robotic-arm assisted surgery platform.',
  'BSX': 'Boston Scientific manufactures medical devices used in interventional cardiology, cardiac rhythm management, endoscopy, urology, and neuromodulation. The company serves hospitals and outpatient facilities worldwide and has grown through both organic innovation and strategic acquisitions.',

  // Consumer
  'WMT': 'Walmart is the world\'s largest retailer by revenue, operating thousands of stores across the United States and internationally under various banners. The company has built a substantial e-commerce and advertising business and serves hundreds of millions of customers weekly.',
  'COST': 'Costco Wholesale operates a chain of membership-only warehouse clubs offering bulk products at discounted prices. The company is known for its low-margin, high-volume business model, strong private label brand (Kirkland Signature), and exceptional customer and employee loyalty.',
  'HD': 'Home Depot is the world\'s largest home improvement retailer, operating thousands of warehouse-format stores across North America. The company serves both do-it-yourself consumers and professional contractors with building materials, home improvement products, and installation services.',
  'LOW': 'Lowe\'s Companies is the second-largest home improvement retailer in the United States, operating stores that offer products for construction, maintenance, home repair, remodeling, and decorating. The company competes primarily with Home Depot and has been investing in its omnichannel capabilities and professional customer segment.',
  'NKE': 'Nike is the world\'s largest athletic footwear and apparel company, selling products under the Nike, Jordan, and Converse brands. The company is known for its marketing, athlete endorsements, and innovation in performance sportswear, and has been shifting toward direct-to-consumer sales.',
  'SBUX': 'Starbucks is the world\'s largest coffeehouse chain, operating tens of thousands of stores across more than 80 countries. The company has built a powerful brand in specialty coffee and expanded into packaged goods, ready-to-drink beverages, and a highly successful mobile ordering and loyalty platform.',
  'MCD': 'McDonald\'s is the world\'s largest fast-food restaurant chain by revenue, operating and franchising tens of thousands of restaurants globally. The company\'s franchise-heavy model generates high margins and consistent cash flow, supported by iconic menu items and extensive real estate holdings.',
  'DIS': 'The Walt Disney Company is a global entertainment conglomerate operating theme parks, cruise lines, studios (Walt Disney Studios, Pixar, Marvel, Lucasfilm, 20th Century Studios), and streaming services including Disney+, Hulu, and ESPN+. The company owns some of the most valuable entertainment franchises in the world.',
  'KO': 'The Coca-Cola Company is the world\'s largest beverage company, selling more than 200 brands of soft drinks, water, juice, tea, coffee, and sports drinks across over 200 countries. The company operates primarily as a concentrate manufacturer and brand owner, partnering with bottling companies for production and distribution.',
  'PEP': 'PepsiCo is a global food and beverage company with a diverse portfolio that includes Pepsi, Mountain Dew, Gatorade, Lay\'s, Doritos, Quaker, and Tropicana. The company\'s snack food division (Frito-Lay) is the largest in the world and generates a significant share of its operating profit.',
  'PG': 'Procter & Gamble is the world\'s largest consumer packaged goods company, manufacturing household and personal care products under brands like Tide, Pampers, Gillette, Charmin, and Oral-B. The company sells products in more than 180 countries and is known for its brand management expertise and operational efficiency.',
  'MO': 'Altria Group is one of the world\'s largest tobacco companies, primarily selling Marlboro cigarettes in the United States through Philip Morris USA. The company also holds a significant stake in Anheuser-Busch InBev and has invested in smoke-free alternatives including heated tobacco and oral nicotine products.',
  'PM': 'Philip Morris International manufactures and sells cigarettes and smoke-free products outside the United States, with a portfolio including Marlboro and the IQOS heated tobacco system. The company has been transitioning its business toward reduced-risk products and aims to become predominantly a smoke-free company.',
  'TGT': 'Target is a major U.S. retailer operating nearly 2,000 stores across all 50 states, offering a curated assortment of apparel, home goods, groceries, electronics, and beauty products. The company differentiates through exclusive private-label brands, store design, and same-day fulfillment services.',
  'LULU': 'Lululemon Athletica is a premium athletic apparel company known for its yoga pants, running gear, and lifestyle clothing. The company has built a strong brand through community-driven marketing, technical fabric innovation, and a growing men\'s and international business.',
  'CMG': 'Chipotle Mexican Grill operates a chain of fast-casual restaurants serving burritos, tacos, and bowls made with fresh ingredients. The company is known for its food-with-integrity philosophy, customizable menu, and strong digital ordering and loyalty program.',
  'YUM': 'Yum! Brands operates and franchises three of the world\'s largest quick-service restaurant brands: KFC, Taco Bell, and Pizza Hut, with tens of thousands of locations across more than 150 countries. The company\'s asset-light franchise model generates stable, high-margin earnings.',

  // Energy
  'XOM': 'ExxonMobil is the largest publicly traded oil and gas company in the world by market capitalization, with operations spanning exploration, production, refining, and chemical manufacturing. The company has major upstream assets in the Permian Basin and Guyana and maintains one of the largest refining networks globally.',
  'CVX': 'Chevron is one of the world\'s largest integrated energy companies, engaged in oil and gas exploration, production, refining, and petrochemical operations. The company has significant assets in the Permian Basin, Australia LNG, and deepwater Gulf of Mexico, and is investing in lower-carbon energy technologies.',
  'COP': 'ConocoPhillips is one of the largest independent exploration and production companies in the world, focused on finding and producing crude oil, natural gas, and natural gas liquids. The company has major operations in Alaska, the Lower 48, Canada, and international basins.',
  'SLB': 'SLB (formerly Schlumberger) is the world\'s largest oilfield services company, providing technology and services for oil and gas exploration, drilling, production, and processing. The company operates in more than 100 countries and offers digital and automation solutions for the energy industry.',
  'EOG': 'EOG Resources is one of the largest independent crude oil and natural gas exploration and production companies in the United States. The company is known for its premium drilling strategy, operational efficiency, and strong returns to shareholders from assets in the Permian Basin, Eagle Ford, and other plays.',
  'OXY': 'Occidental Petroleum is an energy company engaged in oil and gas exploration and production, chemical manufacturing through OxyChem, and carbon management solutions. The company has significant assets in the Permian Basin and is a leading investor in direct air capture technology for carbon dioxide removal.',

  // Industrial
  'BA': 'Boeing is the world\'s largest aerospace company, manufacturing commercial jetliners, defense systems, satellites, and launch vehicles. The company is one of only two major manufacturers of large commercial aircraft globally and a significant U.S. defense contractor.',
  'CAT': 'Caterpillar is the world\'s largest manufacturer of construction and mining equipment, diesel and natural gas engines, industrial gas turbines, and diesel-electric locomotives. The company serves customers in construction, resource industries, energy, and transportation through a global dealer network.',
  'GE': 'GE Aerospace (formerly General Electric) focuses on jet engines and aviation systems after completing its separation into three independent companies. The company is one of the world\'s largest jet engine manufacturers, powering commercial and military aircraft with its LEAP and GE9X engines.',
  'RTX': 'RTX Corporation (formerly Raytheon Technologies) is one of the world\'s largest aerospace and defense companies, combining Pratt & Whitney jet engines, Collins Aerospace systems, and Raytheon missile and defense electronics. The company serves both commercial aviation and military customers globally.',
  'HON': 'Honeywell International is a diversified technology and manufacturing company operating in aerospace, building technologies, performance materials, and industrial automation. The company produces aircraft engines, navigation systems, building management solutions, and advanced materials used across multiple industries.',
  'LMT': 'Lockheed Martin is the world\'s largest defense contractor, producing advanced military aircraft including the F-35 Lightning II, missile defense systems, space systems, and rotary aircraft like the Sikorsky Black Hawk helicopter. The company is a critical supplier to the U.S. Department of Defense and allied nations.',
  'UPS': 'United Parcel Service is the world\'s largest package delivery company by revenue, providing domestic and international package delivery, freight transportation, and supply chain management services. The company operates one of the largest airline fleets in the world and delivers millions of packages daily.',
  'DE': 'Deere & Company (John Deere) is the world\'s largest manufacturer of agricultural machinery, producing tractors, combines, planters, and precision agriculture technology. The company also manufactures construction and forestry equipment and is a leader in integrating GPS, sensors, and AI into farming operations.',
  'MMM': 'Minnesota Mining and Manufacturing (3M) is a diversified technology company producing thousands of products across safety and industrial, transportation and electronics, healthcare, and consumer segments. The company is known for brands like Post-it Notes, Scotch tape, and N95 respirators.',

  // Telecom/Media
  'T': 'AT&T is one of the largest telecommunications companies in the United States, providing wireless services, broadband, and fiber internet to tens of millions of customers. The company has refocused on connectivity after divesting its media assets, including WarnerMedia.',
  'VZ': 'Verizon Communications is a leading U.S. telecommunications company providing wireless, broadband, and fiber optic services to consumers, businesses, and government customers. The company operates the largest wireless network in the United States by subscribers.',
  'TMUS': 'T-Mobile US is the second-largest wireless carrier in the United States, known for its disruptive pricing, customer-friendly policies, and rapid network expansion following its merger with Sprint. The company has aggressively deployed 5G coverage and gained market share from AT&T and Verizon.',
  'CMCSA': 'Comcast Corporation is the largest cable television and internet service provider in the United States, also owning NBCUniversal (including NBC, Universal Studios, and theme parks) and Sky in Europe. The company provides broadband, video, and phone services to tens of millions of households.',
  'CHTR': 'Charter Communications operates the Spectrum brand of cable television, internet, and telephone services, making it one of the largest broadband providers in the United States. The company serves tens of millions of customers across 41 states.',

  // Real Estate
  'AMT': 'American Tower Corporation is one of the largest global real estate investment trusts, owning and operating over 200,000 wireless communication towers and data center facilities worldwide. The company leases space on its towers to wireless carriers and generates stable, recurring revenue from long-term contracts.',
  'PLD': 'Prologis is the world\'s largest industrial real estate company, owning and managing logistics facilities including warehouses and distribution centers across the Americas, Europe, and Asia. The company is a key beneficiary of e-commerce growth, serving customers like Amazon, FedEx, and major retailers.',
  'EQIX': 'Equinix is the world\'s largest data center REIT, operating over 260 data center facilities across six continents. The company provides colocation, interconnection, and digital infrastructure services to enterprises, cloud providers, and network operators globally.',
  'DLR': 'Digital Realty Trust is one of the largest global providers of data center, colocation, and interconnection solutions, operating facilities across North America, Europe, Asia, and Australia. The company serves a diverse customer base including cloud providers, IT service providers, and enterprises.',
  'SPG': 'Simon Property Group is the largest shopping mall owner and operator in the United States, with a portfolio of premier retail properties including malls, outlets, and mixed-use destinations. The company also has international investments and has been diversifying into non-retail uses.',
  'O': 'Realty Income Corporation is a real estate investment trust that owns thousands of commercial properties leased to retail and industrial tenants under long-term net lease agreements. Known as "The Monthly Dividend Company," it is popular among income-focused investors for its consistent monthly dividend payments.',

  // Crypto-Related
  'MARA': 'Marathon Digital Holdings is one of the largest publicly traded cryptocurrency mining companies in the United States, operating large-scale mining facilities to produce Bitcoin. The company has invested heavily in expanding its hash rate capacity and energy infrastructure.',
  'RIOT': 'Riot Platforms is a cryptocurrency mining company focused on Bitcoin mining, data center hosting, and electrical switchgear engineering. The company operates one of the largest Bitcoin mining facilities in North America and is expanding its capacity.',
  'MSTR': 'MicroStrategy is a business intelligence software company that has become known primarily for its large-scale Bitcoin acquisition strategy. The company holds a substantial Bitcoin treasury and has used equity and convertible debt offerings to fund its cryptocurrency purchases, making its stock a popular proxy for Bitcoin exposure.',

  // International
  'ASML': 'ASML Holding is a Dutch semiconductor equipment manufacturer that holds a monopoly on extreme ultraviolet (EUV) lithography machines essential for producing the most advanced semiconductor chips. The company is one of the most critical suppliers in the global chip supply chain, serving TSMC, Samsung, and Intel.',
  'TSM': 'Taiwan Semiconductor Manufacturing Company (TSMC) is the world\'s largest contract chipmaker, manufacturing semiconductors for companies including Apple, NVIDIA, AMD, and Qualcomm. The company leads the industry in advanced process technology and produces the majority of the world\'s most advanced chips.',
  'BABA': 'Alibaba Group is China\'s largest e-commerce company, operating Taobao, Tmall, and international platforms, along with cloud computing services through Alibaba Cloud. The company also has significant interests in digital payments (Ant Group), logistics (Cainiao), and entertainment.',
  'TCEHY': 'Tencent Holdings is a Chinese technology conglomerate and one of the world\'s largest companies by market capitalization. The company operates WeChat (China\'s dominant super-app), is the world\'s largest video game publisher, and has major investments in fintech, cloud computing, and digital entertainment.',
  'SHEL': 'Shell is one of the world\'s largest integrated energy companies, engaged in exploration, production, refining, and trading of oil and natural gas, as well as chemicals and renewables. Headquartered in London, the company operates across more than 70 countries and is investing in the energy transition.',
  'AZN': 'AstraZeneca is a British-Swedish multinational pharmaceutical and biotechnology company focused on oncology, cardiovascular, renal, metabolism, and respiratory and immunology therapies. The company has been one of the fastest-growing large-cap pharma companies, driven by its oncology portfolio and strategic acquisitions.',
  'SAP': 'SAP is a German multinational software company and the world\'s largest enterprise resource planning (ERP) software vendor. The company\'s products help businesses manage operations, finances, human resources, and supply chains, and it is transitioning customers to its cloud-based S/4HANA platform.',
  'TM': 'Toyota Motor Corporation is the world\'s largest automaker by vehicle sales, manufacturing a broad range of vehicles from economy cars to luxury models under the Toyota and Lexus brands. The company pioneered hybrid vehicle technology with the Prius and is investing in hydrogen fuel cells, battery EVs, and solid-state batteries.',
  'HSBA.UK': 'HSBC Holdings is one of the world\'s largest banking and financial services organizations, serving customers in Europe, Asia, the Middle East, and the Americas. The bank has a particularly strong presence in Asia and Hong Kong, which generates the majority of its profits.',
  'BP.UK': 'BP is a British multinational oil and gas company engaged in exploration, production, refining, distribution, and marketing of energy products worldwide. The company has set ambitious targets to transition its business toward lower-carbon energy, investing in renewables, EV charging, and hydrogen.',
  'ULVR.UK': 'Unilever is a British-Dutch consumer goods company operating in beauty and personal care, home care, and food and refreshment segments. The company owns well-known brands including Dove, Ben & Jerry\'s, Hellmann\'s, and Knorr, serving billions of consumers globally.',
  'GSK.UK': 'GSK (formerly GlaxoSmithKline) is a British pharmaceutical and biotechnology company focused on innovative medicines, vaccines, and consumer healthcare. The company has refocused on biopharma following the demerger of its consumer health division as Haleon.',
  'NESTLE.EU': 'Nestle is the world\'s largest food and beverage company by revenue, headquartered in Switzerland and operating in nearly every country. The company\'s portfolio includes brands like Nescafe, KitKat, Purina, Gerber, and Nespresso, spanning coffee, pet care, infant nutrition, water, and confectionery.',
  'LVMH.EU': 'LVMH Moet Hennessy Louis Vuitton is the world\'s largest luxury goods conglomerate, owning over 75 prestigious brands across fashion and leather goods, wines and spirits, perfumes and cosmetics, watches and jewelry, and selective retailing. Key brands include Louis Vuitton, Christian Dior, Hennessy, Tiffany & Co., and Sephora.',
  'SAMSUNG.KR': 'Samsung Electronics is a South Korean multinational and one of the world\'s largest technology companies, leading in smartphones, memory semiconductors, display panels, and consumer electronics. The company is the dominant manufacturer of DRAM and NAND flash memory and competes with TSMC in advanced semiconductor foundry services.',

  // Additional well-known companies - Semiconductors
  'MU': 'Micron Technology designs and manufactures memory and storage semiconductor products, including DRAM, NAND flash, and NOR flash memory. The company is one of only three major DRAM manufacturers globally and a critical supplier of memory chips for data centers, smartphones, and PCs.',
  'MRVL': 'Marvell Technology designs and sells semiconductor solutions for data infrastructure including cloud data centers, enterprise networking, carrier infrastructure, and consumer devices. The company has positioned itself as a key supplier of custom and semi-custom chips for cloud computing and 5G networks.',
  'TXN': 'Texas Instruments designs and manufactures analog and embedded processing semiconductors used in industrial, automotive, personal electronics, and communications equipment. The company is the world\'s largest analog chip maker and owns its own manufacturing facilities, providing a structural cost advantage.',
  'ADI': 'Analog Devices designs and manufactures high-performance analog, mixed-signal, and digital signal processing integrated circuits for industrial, automotive, consumer, and communications applications. The company strengthened its market position through its merger with Maxim Integrated.',
  'LRCX': 'Lam Research designs, manufactures, and services semiconductor processing equipment used in the fabrication of integrated circuits. The company is a leading supplier of etch and deposition equipment essential to chipmaking, benefiting from increasing complexity in semiconductor manufacturing.',
  'AMAT': 'Applied Materials is the world\'s largest semiconductor equipment manufacturer, providing materials engineering solutions for the production of semiconductor chips, flat panel displays, and solar photovoltaic products. The company\'s equipment is essential to nearly every step of chipmaking.',
  'KLAC': 'KLA Corporation designs and manufactures process control and yield management systems for the semiconductor and related electronics industries. The company\'s inspection and metrology equipment is critical for detecting defects and ensuring quality in chip manufacturing.',
  'ON': 'ON Semiconductor designs and manufactures intelligent sensing and power solutions for automotive, industrial, and cloud infrastructure applications. The company is a leading supplier of image sensors for automotive ADAS and silicon carbide chips for electric vehicle power systems.',
  'NXPI': 'NXP Semiconductors is a Dutch semiconductor company specializing in automotive, industrial, IoT, mobile, and communication infrastructure chips. The company is a leading supplier of automotive semiconductors for in-vehicle networking, driver assistance systems, and vehicle electrification.',
  'SWKS': 'Skyworks Solutions designs and manufactures analog and mixed-signal semiconductors for mobile communications, automotive, broadband, and IoT applications. The company is a major supplier of RF chips that enable wireless connectivity in smartphones and other devices.',

  // Additional well-known companies - Software & Cloud
  'INTU': 'Intuit develops financial management and tax preparation software for consumers and small businesses, including TurboTax, QuickBooks, Credit Karma, and Mailchimp. The company dominates the U.S. consumer tax preparation and small business accounting markets.',
  'WDAY': 'Workday provides cloud-based enterprise software for human capital management and financial management to large organizations. The company has become the standard for cloud HR and finance systems, replacing legacy on-premise solutions from SAP and Oracle.',
  'TEAM': 'Atlassian develops collaboration and project management software including Jira, Confluence, Trello, and Bitbucket used by software development and IT teams worldwide. The company operates with an efficient go-to-market model that relies on self-service adoption rather than large sales teams.',
  'HUBS': 'HubSpot provides cloud-based customer relationship management, marketing, sales, and customer service software for small and medium-sized businesses. The company\'s all-in-one inbound marketing platform has gained strong adoption among growing companies.',
  'MDB': 'MongoDB provides a general-purpose, document-based database platform used by developers to build and run modern applications. The company\'s Atlas cloud database service has driven rapid revenue growth as organizations adopt NoSQL databases for flexible data management.',
  'OKTA': 'Okta provides cloud-based identity and access management solutions that enable organizations to securely connect people to technology. The company is a leader in workforce and customer identity management, helping enterprises manage authentication, authorization, and single sign-on.',
  'TTD': 'The Trade Desk operates a demand-side platform that enables advertisers to purchase and manage digital advertising campaigns across channels including connected TV, display, mobile, audio, and social media. The company is the largest independent programmatic advertising platform.',
  'VEEV': 'Veeva Systems provides cloud-based software specifically designed for the life sciences industry, including CRM, content management, regulatory, and clinical trial solutions. The company holds a dominant position in life sciences CRM and is expanding into broader industry-specific cloud applications.',
  'ZM': 'Zoom Communications provides video conferencing, online meetings, chat, and collaboration solutions for businesses and individuals worldwide. The company experienced explosive growth during the COVID-19 pandemic and continues to expand its platform into contact center, email, and phone services.',
  'DOCU': 'DocuSign provides electronic signature and digital agreement management solutions that enable organizations to sign, send, and manage documents electronically. The company pioneered the e-signature category and is expanding into broader agreement lifecycle management.',
  'MNDY': 'monday.com develops a cloud-based Work OS platform that enables organizations to build custom work management tools for project management, CRM, software development, and other workflows. The company serves businesses of all sizes with a flexible, no-code platform.',
  'U': 'Unity Technologies provides a real-time 3D development platform used to create interactive experiences including video games, architectural visualizations, and training simulations. The company also operates an advertising network and provides tools for creating content across mobile, PC, console, and AR/VR platforms.',
  'PATH': 'UiPath provides enterprise automation software, specializing in robotic process automation (RPA) that enables organizations to automate repetitive business processes. The company\'s platform uses AI and software robots to automate tasks across back-office operations, customer service, and IT.',
  'CFLT': 'Confluent provides a data streaming platform based on Apache Kafka that enables organizations to process and manage real-time data streams. The company helps enterprises build applications that react to events in real time, serving sectors from financial services to retail.',
  'ESTC': 'Elastic provides search, observability, and security solutions powered by its open-source Elasticsearch platform. The company\'s technology is used for enterprise search, application performance monitoring, log analytics, and security information and event management.',

  // Additional well-known companies - Fintech & Financial Services
  'FIS': 'Fidelity National Information Services (FIS) is one of the world\'s largest fintech companies, providing payment processing, banking technology, and capital markets solutions to financial institutions. The company serves thousands of financial institutions and processes trillions of dollars in transactions annually.',
  'FISV': 'Fiserv is a global fintech company providing payments processing, financial services technology, and merchant acquiring solutions. The company serves banks, credit unions, and merchants through products including the Clover point-of-sale platform and Zelle payment network integration.',
  'GPN': 'Global Payments provides payment technology and software solutions to merchants, issuers, and consumers worldwide. The company processes billions of transactions annually and has expanded into integrated software and payments solutions for specific industry verticals.',
  'AFRM': 'Affirm Holdings provides buy-now-pay-later (BNPL) financing solutions that allow consumers to split purchases into installments at the point of sale. The company partners with major retailers and e-commerce platforms and differentiates by not charging late fees or hidden charges.',
  'SOFI': 'SoFi Technologies is a digital personal finance company offering a range of financial products including student loan refinancing, personal loans, mortgages, investing, banking, and credit cards through its mobile app. The company obtained a national bank charter, enabling it to hold deposits and reduce funding costs.',
  'HOOD': 'Robinhood Markets operates a commission-free trading platform for stocks, ETFs, options, and cryptocurrencies, primarily through its mobile app. The company popularized zero-commission trading and gamified investing features, attracting millions of retail investors.',

  // Additional well-known companies - E-commerce & Internet
  'BKNG': 'Booking Holdings operates the world\'s largest online travel agency by room nights booked, owning Booking.com, Priceline, Kayak, Agoda, and OpenTable. The company connects travelers with accommodations, flights, rental cars, and restaurant reservations across more than 220 countries.',
  'ABNB': 'Airbnb operates a global online marketplace for short-term lodging, vacation rentals, and experiences, connecting hosts who list their properties with travelers. The company has fundamentally changed the hospitality industry and operates in virtually every country in the world.',
  'DASH': 'DoorDash is the largest food delivery platform in the United States by market share, connecting consumers with restaurants, grocery stores, and convenience stores. The company has expanded internationally and into new delivery verticals beyond restaurant food.',
  'GRAB': 'Grab Holdings operates a superapp platform in Southeast Asia providing ride-hailing, food delivery, package delivery, and financial services across multiple countries. The company is the largest on-demand transportation and delivery platform in the region.',
  'SE': 'Sea Limited is a Southeast Asian technology company operating in digital entertainment (Garena), e-commerce (Shopee), and digital financial services (SeaMoney). Shopee is one of the largest e-commerce platforms in Southeast Asia and has expanded into Latin American markets.',
  'MELI': 'MercadoLibre is the largest e-commerce and fintech ecosystem in Latin America, operating online marketplaces, digital payments (Mercado Pago), logistics, and credit services across 18 countries. The company is often called the "Amazon of Latin America" and has built a rapidly growing fintech business.',
  'ETSY': 'Etsy operates a global online marketplace focused on handmade, vintage, and unique factory-manufactured items spanning jewelry, clothing, home decor, and craft supplies. The company serves millions of active sellers and buyers and differentiates through its focus on creative and artisanal goods.',
  'EBAY': 'eBay operates one of the world\'s largest online marketplaces connecting buyers and sellers of new and used goods across a wide range of categories. The company pioneered online auctions and continues to serve millions of active buyers and sellers globally.',
  'W': 'Wayfair is one of the largest online retailers of home furnishings and decor in the United States, offering millions of products across furniture, lighting, rugs, bedding, and kitchen items. The company operates a drop-ship model where suppliers ship directly to customers.',
  'CHWY': 'Chewy operates the largest online pet retailer in the United States, selling pet food, treats, supplies, and pharmacy products with a focus on autoship subscription services. The company has built strong customer loyalty through personalized service and convenient delivery.',

  // Additional Healthcare & Biotech
  'DXCM': 'DexCom develops and markets continuous glucose monitoring (CGM) systems for diabetes management. The company\'s sensors allow patients to track glucose levels in real time without fingerstick blood tests, and its products are widely adopted by people with Type 1 and Type 2 diabetes.',
  'IDXX': 'IDEXX Laboratories develops diagnostic products and services for veterinary practices, livestock and poultry operations, and water testing. The company is the global leader in veterinary diagnostics, holding a dominant market share in point-of-care and reference lab testing for companion animals.',
  'ZTS': 'Zoetis is the world\'s largest animal health company, developing medicines, vaccines, and diagnostic products for livestock and companion animals. The company was spun off from Pfizer and serves veterinarians, livestock producers, and pet owners worldwide.',
  'A': 'Agilent Technologies provides analytical instruments, software, services, and consumables for the life sciences, diagnostics, and applied chemical markets. The company\'s products are used in pharmaceutical research, environmental testing, food safety, and forensics laboratories.',
  'IQV': 'IQVIA Holdings provides advanced analytics, technology solutions, and clinical research services to the life sciences industry. The company combines healthcare data, technology, and domain expertise to help pharmaceutical and biotech companies develop and commercialize medicines.',
  'EW': 'Edwards Lifesciences is a global leader in heart valves, hemodynamic monitoring, and critical care technologies. The company pioneered transcatheter aortic valve replacement (TAVR) and dominates the structural heart device market.',
  'GEHC': 'GE HealthCare Technologies is a global medical technology and pharmaceutical diagnostics company that was spun off from General Electric. The company provides imaging systems (CT, MRI, X-ray), ultrasound equipment, patient monitoring systems, and pharmaceutical diagnostics.',
  'ALNY': 'Alnylam Pharmaceuticals is a biopharmaceutical company and a leader in RNA interference (RNAi) therapeutics. The company develops and commercializes siRNA medicines that silence disease-causing genes, with approved products treating rare genetic diseases.',

  // Additional Industrials & Aerospace
  'GD': 'General Dynamics is a global aerospace and defense company operating in business aviation (Gulfstream jets), combat vehicles, weapons systems, marine systems (submarines and surface ships), and technology services. The company is a key contractor for the U.S. military and allied nations.',
  'NOC': 'Northrop Grumman is a major aerospace and defense company specializing in advanced aircraft (including the B-21 Raider stealth bomber), space systems, missile defense, and cybersecurity. The company is one of the top U.S. defense contractors and plays a critical role in national security programs.',
  'TDG': 'TransDigm Group designs and produces highly engineered aerospace components and systems used on virtually every commercial and military aircraft in service. The company\'s strategy focuses on proprietary, sole-source products with strong aftermarket demand, generating high margins.',
  'WM': 'Waste Management is the largest waste collection, disposal, and recycling company in North America, operating landfills, transfer stations, recycling facilities, and renewable energy projects. The company serves residential, commercial, and industrial customers across the United States and Canada.',
  'RSG': 'Republic Services is the second-largest waste collection and disposal company in the United States, providing non-hazardous solid waste collection, transfer, recycling, and disposal services. The company operates hundreds of collection operations, transfer stations, and landfills.',
  'ETN': 'Eaton Corporation is a diversified industrial manufacturer specializing in electrical power management, aerospace systems, vehicle components, and eMobility solutions. The company benefits from electrification trends across data centers, utilities, and transportation.',
  'EMR': 'Emerson Electric is a global technology and engineering company providing automation solutions for process, hybrid, and discrete industries, as well as commercial and residential climate technologies. The company has been refocusing its portfolio on industrial automation and software.',
  'ITW': 'Illinois Tool Works (ITW) is a diversified manufacturer of industrial products and equipment operating across seven segments including automotive, food equipment, test and measurement, welding, and polymers. The company is known for its decentralized business model and strong margins.',
  'FDX': 'FedEx Corporation provides transportation, e-commerce, and business services globally, operating through its Express, Ground, Freight, and Services segments. The company is the world\'s largest express delivery network and serves as a critical logistics partner for global commerce.',
  'CARR': 'Carrier Global Corporation is a global provider of heating, ventilation, air conditioning (HVAC), refrigeration, fire, and security solutions for buildings and cold chain applications. The company was spun off from United Technologies and operates iconic brands like Carrier, Kidde, and Edwards.',

  // Additional Consumer & Retail
  'EL': 'The Estee Lauder Companies is a global manufacturer and marketer of premium skincare, makeup, fragrance, and hair care products. The company\'s portfolio includes brands like Estee Lauder, Clinique, MAC, La Mer, Jo Malone, and Tom Ford Beauty.',
  'CL': 'Colgate-Palmolive manufactures and sells consumer products worldwide in oral care, personal care, home care, and pet nutrition (through Hill\'s Pet Nutrition). The company\'s Colgate brand holds the global leadership position in toothpaste and manual toothbrush markets.',
  'KMB': 'Kimberly-Clark manufactures and sells personal care and consumer tissue products globally under brands including Huggies, Kleenex, Scott, and Cottonelle. The company holds leading market positions in diapers, tissue, and professional hygiene products.',
  'MDLZ': 'Mondelez International is a global snacking company with brands including Oreo, Cadbury, Toblerone, Ritz, and Trident, operating in more than 150 countries. The company focuses on chocolate, biscuits, baked snacks, and gum and candy categories.',
  'GIS': 'General Mills is a global food company that manufactures and markets branded consumer foods including Cheerios, Yoplait, Nature Valley, Haagen-Dazs, Old El Paso, and Blue Buffalo pet food. The company sells products across retail stores, foodservice, and pet specialty channels.',
  'K': 'Kellanova (formerly Kellogg Company\'s snacking business) is a global snacking, international cereal, and noodle company with brands including Pringles, Cheez-It, Pop-Tarts, and Eggo. The company separated from WK Kellogg Co, which retained the North American cereal business.',
  'MNST': 'Monster Beverage Corporation develops and markets energy drinks and alternative beverages under brands including Monster Energy, Reign, and Bang. The company is the second-largest energy drink maker globally and benefits from a distribution partnership with Coca-Cola.',
  'DEO': 'Diageo is the world\'s largest spirits company, producing and distributing iconic premium beverage brands including Johnnie Walker, Guinness, Smirnoff, Tanqueray, Captain Morgan, and Don Julio. The company operates in more than 180 countries.',
  'ROST': 'Ross Stores operates a chain of off-price retail stores under the Ross Dress for Less and dd\'s DISCOUNTS brands in the United States. The company sells name-brand and designer apparel, accessories, footwear, and home goods at significant discounts to department store prices.',
  'TJX': 'TJX Companies is the world\'s largest off-price retailer, operating T.J. Maxx, Marshalls, HomeGoods, Sierra, and international stores across nine countries. The company\'s opportunistic buying model offers brand-name merchandise at 20-60% below department store prices.',
  'ORLY': 'O\'Reilly Automotive is one of the largest specialty retailers of automotive aftermarket parts, tools, supplies, and accessories in the United States. The company operates thousands of stores and serves both do-it-yourself customers and professional repair shops.',
  'AZO': 'AutoZone is the largest retailer of automotive replacement parts and accessories in the United States, operating thousands of stores domestically and in Mexico and Brazil. The company serves both DIY customers and commercial repair shops with a vast inventory of parts and free diagnostic services.',

  // Additional Financials & Insurance
  'PGR': 'Progressive Corporation is one of the largest auto insurance providers in the United States, known for its direct-to-consumer model, usage-based insurance products, and competitive pricing. The company has consistently gained market share through technology-driven underwriting and claims processing.',
  'TRV': 'The Travelers Companies is one of the largest property and casualty insurers in the United States, providing commercial and personal insurance products including workers\' compensation, auto, and homeowners insurance. The company is a component of the Dow Jones Industrial Average.',
  'AON': 'Aon is a global professional services firm providing risk management, insurance brokerage, reinsurance, and human capital consulting services. The company is one of the two largest insurance brokers in the world, serving commercial, institutional, and individual clients.',
  'MMC': 'Marsh McLennan is the world\'s largest insurance broker and risk management firm, operating through Marsh, Guy Carpenter, Mercer, and Oliver Wyman. The company provides insurance brokerage, reinsurance, risk consulting, and human resources consulting services.',
  'CB': 'Chubb is the world\'s largest publicly traded property and casualty insurer, offering commercial and personal insurance products including specialty lines, reinsurance, and life insurance. The company operates in 54 countries and is known for its underwriting discipline and high-net-worth personal lines business.',
  'MCO': 'Moody\'s Corporation provides credit ratings, research, and risk analysis for debt securities and is one of the three major credit rating agencies globally. The company\'s analytics division provides financial data, analytical tools, and risk management solutions.',
  'MSCI': 'MSCI provides decision support tools for institutional investors, including equity and fixed income indexes, portfolio risk analytics, and ESG and climate data. The company\'s indexes are benchmarks for trillions of dollars in assets and are widely used in ETF construction.',
  'COF': 'Capital One Financial Corporation is a bank holding company specializing in credit cards, consumer banking, and commercial lending. The company is one of the largest credit card issuers in the United States and is known for its data-driven approach to marketing and risk management.',
  'AIG': 'American International Group (AIG) is a global insurance company providing property-casualty insurance, life and retirement solutions, and financial services. The company serves commercial, institutional, and individual customers worldwide and has simplified its business after years of restructuring.',

  // Additional Energy & Utilities
  'NEE': 'NextEra Energy is the world\'s largest producer of wind and solar energy and the parent company of Florida Power & Light, one of the largest electric utilities in the United States. The company operates through its regulated utility and its clean energy development subsidiary, NextEra Energy Resources.',
  'ENPH': 'Enphase Energy designs and manufactures solar microinverters, battery storage systems, and energy management technology for residential and commercial solar installations. The company\'s microinverter technology has become an industry standard for converting solar panel DC power to grid-compatible AC power.',
  'FSLR': 'First Solar manufactures thin-film photovoltaic solar modules and develops utility-scale solar power plants. The company is the largest U.S.-headquartered solar panel manufacturer and benefits from domestic content requirements and tariffs on imported solar panels.',
  'LNG': 'Cheniere Energy is the largest producer and exporter of liquefied natural gas (LNG) in the United States, operating the Sabine Pass and Corpus Christi LNG terminals. The company has played a pivotal role in making the U.S. a major global LNG supplier.',
  'PSA': 'Public Storage is the largest self-storage REIT in the United States, owning and operating thousands of self-storage facilities across the country and Europe. The company benefits from strong demand for storage space and operates under a low-cost, high-margin business model.',
  'D': 'Dominion Energy is one of the largest producers and distributors of electricity and natural gas in the United States, serving millions of customers in Virginia, the Carolinas, and other states. The company operates regulated utility businesses and is investing in offshore wind energy.',
  'DUK': 'Duke Energy is one of the largest electric power holding companies in the United States, providing electricity to millions of customers in the Carolinas, Florida, Indiana, Ohio, and Kentucky. The company is investing heavily in grid modernization, renewable energy, and the clean energy transition.',
  'SO': 'Southern Company is one of the largest electric utility holding companies in the United States, providing electricity and natural gas to millions of customers across the Southeast. The company operates regulated utilities in Georgia, Alabama, Mississippi, and Virginia.',

  // Additional Tech & Communications
  'TOST': 'Toast provides cloud-based restaurant management technology, including point-of-sale systems, payment processing, digital ordering, and operations management software. The company has quickly gained market share in the restaurant technology sector.',
  'TWLO': 'Twilio provides cloud-based communication APIs that enable developers to embed voice, messaging, video, and authentication capabilities into applications. The company serves hundreds of thousands of customers and is the leading communications platform-as-a-service (CPaaS) provider.',
  'ROKU': 'Roku manufactures streaming media players and licenses its operating system to smart TV manufacturers, making it one of the most widely used streaming platforms in North America. The company generates the majority of its revenue from advertising sold on its platform.',
  'BILL': 'BILL Holdings provides cloud-based financial operations software that automates back-office financial processes for small and mid-sized businesses. The company\'s platform helps businesses manage accounts payable, accounts receivable, and spend management.',
  'AKAM': 'Akamai Technologies operates one of the world\'s largest content delivery networks (CDNs), providing cloud and cybersecurity services for delivering and protecting web content and applications. The company is expanding from content delivery into cloud computing and security.',
  'GDDY': 'GoDaddy provides domain name registration, website hosting, website building tools, and online marketing services for small businesses and individuals. The company is the world\'s largest domain registrar, managing hundreds of millions of domains.',
  'DBX': 'Dropbox provides cloud-based file storage, synchronization, and collaboration tools for individuals and businesses. The company serves hundreds of millions of registered users and has expanded into document workflows, e-signatures, and team collaboration features.',
  'LYFT': 'Lyft operates a ride-hailing platform in the United States and Canada, connecting riders with drivers through its mobile app. The company is the second-largest ride-sharing platform in North America and also offers bike and scooter rentals in select cities.',
  'MTCH': 'Match Group operates the world\'s largest portfolio of online dating platforms, including Tinder, Hinge, Match.com, OkCupid, and Plenty of Fish. The company serves users in nearly 200 countries and generates revenue primarily through subscriptions and in-app purchases.',

  // Additional Industrials & Materials
  'LIN': 'Linde is the world\'s largest industrial gases company, producing and distributing atmospheric gases (oxygen, nitrogen, argon), process gases (hydrogen, carbon dioxide), and specialty gases for healthcare, manufacturing, food, and electronics industries. The company was formed through the merger of Linde AG and Praxair.',
  'APD': 'Air Products and Chemicals provides industrial gases, performance materials, and equipment to customers in dozens of industries worldwide. The company is a leading supplier of hydrogen, a key growth area given the energy transition, and operates large-scale gasification and LNG facilities.',
  'SHW': 'Sherwin-Williams is the world\'s largest paint and coatings company, manufacturing and selling products under brands including Sherwin-Williams, Valspar, and Minwax. The company operates thousands of company-owned stores and supplies architectural, industrial, and automotive coatings.',
  'ECL': 'Ecolab provides water treatment, hygiene, and infection prevention products and services to food, healthcare, industrial, energy, and hospitality customers worldwide. The company helps businesses maintain clean and safe environments while reducing water and energy consumption.',
  'CTAS': 'Cintas Corporation provides corporate identity uniforms, work apparel, facility services, first aid and safety supplies, and fire protection products and services to businesses across North America. The company serves over a million businesses through its route-based service delivery model.',
  'VRSK': 'Verisk Analytics provides data analytics and risk assessment solutions for the insurance, energy, and financial services industries. The company\'s data and analytics help insurers with underwriting, claims management, and fraud detection.',
  'CPRT': 'Copart operates online auctions for salvage and clean-title vehicles, connecting sellers (primarily insurance companies) with buyers worldwide. The company processes millions of vehicles annually and has built a global network of storage facilities.',
  'CMI': 'Cummins designs, manufactures, and distributes diesel and alternative fuel engines, power generation systems, and related technologies for commercial and industrial applications worldwide. The company is a leading supplier of truck engines and is developing hydrogen and battery-electric powertrains.',
  'ROK': 'Rockwell Automation provides industrial automation and digital transformation solutions, including programmable logic controllers, software, and industrial IoT platforms. The company is a leading supplier of factory automation technology to manufacturing businesses worldwide.',
  'AME': 'AMETEK is a global manufacturer of electronic instruments and electromechanical devices for process, aerospace, power, and industrial markets. The company operates through two segments and has built its portfolio through disciplined acquisitions and operational improvement.',
  'DOV': 'Dover Corporation is a diversified global industrial manufacturer providing equipment and solutions across five segments: engineered products, clean energy and fueling, imaging and identification, pumps and process solutions, and climate and sustainability technologies. The company serves a broad range of end markets.',

  // Additional Autos & Transportation
  'F': 'Ford Motor Company is one of the world\'s largest automakers, manufacturing cars, trucks, and SUVs under the Ford and Lincoln brands. The company is investing heavily in electric vehicles through its Ford Model e division and maintains a dominant position in the U.S. truck market with the F-Series.',
  'GM': 'General Motors is one of the largest automakers globally, manufacturing vehicles under the Chevrolet, Buick, GMC, and Cadillac brands. The company is investing billions in electric vehicles using its Ultium battery platform and has a growing autonomous vehicle division, Cruise.',
  'RIVN': 'Rivian Automotive designs and manufactures electric vehicles including the R1T pickup truck, R1S SUV, and commercial delivery vans. The company has a partnership with Amazon to produce electric delivery vehicles and operates its own manufacturing facility in Normal, Illinois.',
  'LCID': 'Lucid Group designs and manufactures luxury electric vehicles, with its flagship Lucid Air sedan featuring industry-leading range and performance specifications. The company operates an advanced manufacturing plant in Arizona and is backed by Saudi Arabia\'s Public Investment Fund.',
  'DAL': 'Delta Air Lines is one of the largest airlines in the United States and globally, operating an extensive domestic and international route network. The company is known for its operational reliability, premium travel products, and valuable SkyMiles loyalty program.',
  'UAL': 'United Airlines Holdings operates one of the world\'s largest airline networks, providing domestic and international passenger and cargo air transportation. The company has its primary hub at Chicago O\'Hare and operates a large fleet connecting hundreds of destinations worldwide.',
  'LUV': 'Southwest Airlines is the largest domestic airline in the United States by passengers carried, operating a point-to-point route network with a single aircraft type (Boeing 737). The company is known for its low-cost model, no baggage fees, and employee-focused culture.',

  // Additional Media & Entertainment
  'WBD': 'Warner Bros. Discovery is a global media and entertainment company formed by the merger of WarnerMedia and Discovery. The company owns Warner Bros. film and TV studios, HBO, CNN, Discovery Channel, and the Max streaming platform.',
  'PARA': 'Paramount Global is a media and entertainment company owning CBS, Paramount Pictures, Showtime, MTV, Nickelodeon, Comedy Central, and the Paramount+ streaming service. The company produces and distributes content across film, television, and streaming platforms.',
  'LYV': 'Live Nation Entertainment is the world\'s largest live entertainment company, operating as a concert promoter, venue operator, ticketing service (Ticketmaster), and artist management firm. The company promotes tens of thousands of events annually and operates hundreds of venues worldwide.',
  'EA': 'Electronic Arts is one of the world\'s largest video game publishers, developing and distributing games including EA Sports FC (formerly FIFA), Madden NFL, The Sims, Battlefield, and Apex Legends. The company generates revenue through full-game sales, live services, and in-game transactions.',
  'TTWO': 'Take-Two Interactive Software develops, publishes, and markets interactive entertainment including the Grand Theft Auto, Red Dead Redemption, NBA 2K, and Civilization franchises through its Rockstar Games, 2K, and other labels. The company is known for blockbuster game releases and strong recurring revenue from online modes.',
  'ATVI': 'Activision Blizzard (now part of Microsoft) developed and published video games including Call of Duty, World of Warcraft, Overwatch, and Candy Crush. The company was acquired by Microsoft in 2023 and is now part of Microsoft Gaming.',

  // Additional Pharma & Life Sciences
  'CI': 'The Cigna Group is a global health services company providing health insurance, pharmacy benefit management through Express Scripts, and related services to employers, individuals, and government programs. The company serves hundreds of millions of customer relationships worldwide.',
  'ELV': 'Elevance Health (formerly Anthem) is one of the largest health insurance companies in the United States, providing medical, pharmacy, dental, and vision benefits to tens of millions of members. The company is the largest licensee of the Blue Cross Blue Shield brand.',
  'HUM': 'Humana is a leading health insurance company focused primarily on Medicare Advantage plans for seniors, making it one of the largest participants in the government-sponsored Medicare market. The company also offers commercial insurance and home health services through CenterWell.',
  'CVS': 'CVS Health operates the largest pharmacy chain in the United States, a pharmacy benefit manager (CVS Caremark), and a health insurance company (Aetna). The company has been building an integrated healthcare platform connecting its retail pharmacies, insurance, and healthcare delivery services.',
  'MCK': 'McKesson Corporation is the largest pharmaceutical distributor in the United States, delivering medicines and healthcare products to pharmacies, hospitals, and health systems. The company also provides health information technology, medical supplies, and care management tools.',
  'BIIB': 'Biogen is a biotechnology company focused on neurological and neurodegenerative diseases, including multiple sclerosis, Alzheimer\'s disease, and spinal muscular atrophy. The company\'s portfolio includes Tecfidera, Spinraza, and Leqembi (co-developed with Eisai for Alzheimer\'s).',

  // Additional REITs & Infrastructure
  'CCI': 'Crown Castle International is one of the largest providers of shared wireless infrastructure in the United States, owning and leasing cell towers, small cells, and fiber optic cable. The company\'s assets are critical to wireless network coverage and 5G deployment.',
  'WELL': 'Welltower is the largest healthcare REIT in the United States, investing in senior housing, post-acute care facilities, and outpatient medical office buildings. The company partners with leading healthcare operators and benefits from the aging U.S. population.',
  'AVB': 'AvalonBay Communities is one of the largest apartment REITs in the United States, developing, owning, and operating multifamily communities in high-barrier-to-entry markets along the East and West coasts. The company targets affluent renters in supply-constrained metros.',

  // Space & Aerospace
  'RKLB': 'Rocket Lab USA designs, manufactures, and launches small and medium-lift orbital rockets, with its Electron rocket being one of the most frequently launched commercial rockets globally. The company is developing its larger Neutron rocket and also builds spacecraft, satellite components, and space systems. Often viewed as the closest public-market proxy to SpaceX.',
  'ASTS': 'AST SpaceMobile is building the first space-based cellular broadband network, designed to connect directly to standard smartphones via satellites without any hardware changes. The company aims to eliminate mobile dead zones globally, partnering with major carriers including AT&T, Vodafone, and Rakuten.',
  'LUNR': 'Intuitive Machines is a space exploration company that designs, builds, and operates lunar landers and provides lunar payload delivery services. The company made history with the first commercial lunar landing in 2024 and has multiple NASA contracts under the Commercial Lunar Payload Services program.',
  'RDW': 'Redwire Corporation is a space infrastructure company that manufactures spacecraft components, solar arrays, sensors, and in-space manufacturing systems. The company supplies critical hardware to NASA, the Department of Defense, and commercial space operators, positioning it as a key supplier in the growing space economy.',
  'SPCE': 'Virgin Galactic is a spaceflight company developing commercial spaceflights for private individuals and researchers using its reusable spaceplane system. The company offers suborbital space tourism experiences and conducts research missions from Spaceport America in New Mexico.',
  'BKSY': 'BlackSky Technology operates a constellation of high-revisit, high-resolution Earth observation satellites and provides real-time geospatial intelligence and analytics. The company serves government and commercial customers with on-demand satellite imagery and AI-powered insights.',
  'MNTS': 'Momentus provides in-space transportation and infrastructure services using its orbital transfer vehicles, which move satellites from one orbit to another after launch. The company aims to be a space logistics provider, reducing the cost and complexity of satellite deployment.',
  'KTOS': 'Kratos Defense & Security Solutions develops unmanned aerial drones, satellite communications systems, rocket propulsion, and cybersecurity solutions for the U.S. military and intelligence community. The company is a leader in affordable tactical drone systems and space-related defense technologies.',
  'LDOS': 'Leidos Holdings is a major defense, intelligence, and IT services contractor providing solutions in national security, health, and engineering. The company supports NASA, the Department of Defense, and intelligence agencies with space systems, cybersecurity, and large-scale technology programs.',
  'SARO': 'StandardAero is an aerospace services company specializing in maintenance, repair, and overhaul (MRO) of aircraft engines, components, and airframes for commercial, military, and business aviation customers worldwide.',
  'AVAV': 'AeroVironment designs and manufactures small unmanned aircraft systems (drones) and tactical missile systems for military and commercial customers. The company is a leading supplier of small drones to the U.S. Department of Defense and allied nations.',
  'JOBY': 'Joby Aviation is developing an all-electric vertical takeoff and landing (eVTOL) air taxi designed for commercial passenger service. The company aims to launch an aerial ridesharing service and holds FAA certification progress for its piloted, five-seat aircraft.',

  // Additional Misc
  'RACE': 'Ferrari designs, manufactures, and sells luxury high-performance sports cars and operates a licensed merchandise business. The company is one of the most recognized luxury brands in the world, known for exclusivity, Formula 1 racing heritage, and strong pricing power.',
  'RCL': 'Royal Caribbean Group is one of the world\'s largest cruise line operators, owning Royal Caribbean International, Celebrity Cruises, and Silversea Cruises. The company operates a global fleet of ships and is investing in next-generation vessels and private island destinations.',
  'MAR': 'Marriott International is the world\'s largest hotel company, operating and franchising approximately 8,000 properties across 30 brands including Marriott, Sheraton, Westin, Ritz-Carlton, W Hotels, and St. Regis. The company operates an asset-light model focused on management and franchise fees.',
  'HLT': 'Hilton Worldwide Holdings operates a global portfolio of hotels and resorts across brands including Hilton, Conrad, DoubleTree, Hampton, and Waldorf Astoria. The company has thousands of properties worldwide and operates primarily through management and franchise agreements.',
  'WYNN': 'Wynn Resorts operates luxury casino resorts in Las Vegas and Macau, known for premium hospitality, gaming, dining, and entertainment experiences. The company\'s properties cater to high-end customers and include Wynn Las Vegas, Encore, and Wynn Macau.',
  'LVS': 'Las Vegas Sands is a casino and resort company operating integrated resorts in Macau and Singapore, after selling its Las Vegas properties. The company\'s Marina Bay Sands in Singapore and properties in Macau are among the most profitable casino resorts in the world.',

  // Clean Energy / Hydrogen
  'PLUG': 'Plug Power is a leading provider of hydrogen fuel cell systems, green hydrogen production, and hydrogen infrastructure solutions. The company serves material handling, on-road vehicles, and stationary power markets, aiming to build an end-to-end green hydrogen ecosystem.',
  'BE': 'Bloom Energy manufactures solid oxide fuel cells that generate clean, reliable on-site electricity from natural gas or hydrogen. The company serves data centers, hospitals, manufacturers, and utilities seeking distributed power generation with lower emissions.',
  'FCEL': 'FuelCell Energy designs, manufactures, and operates stationary fuel cell power plants that generate electricity cleanly and efficiently. The company\'s platforms can run on natural gas, biogas, or hydrogen and serve utilities, industrial, and government customers.',

  // Gene Editing / Biotech
  'CRSP': 'CRISPR Therapeutics is a gene-editing company focused on developing transformative medicines using its proprietary CRISPR/Cas9 technology. The company gained landmark FDA approval for Casgevy, the first CRISPR-based therapy, treating sickle cell disease and beta thalassemia.',
  'EDIT': 'Editas Medicine is a clinical-stage genome editing company developing transformative medicines using CRISPR technology. The company focuses on treatments for serious diseases including eye disorders, blood diseases, and cancer.',
  'NTLA': 'Intellia Therapeutics is a genome editing company developing CRISPR-based therapies for genetic diseases, with a focus on in vivo (inside the body) gene editing. The company is pioneering treatments for liver diseases, blood disorders, and neurological conditions.',

  // eVTOL
  'ACHR': 'Archer Aviation is developing an all-electric vertical takeoff and landing (eVTOL) aircraft called Midnight for urban air mobility. The company plans to operate an air taxi service and has partnerships with United Airlines and the U.S. Department of Defense.',

  // Rare Earth / Mining
  'MP': 'MP Materials is the largest producer of rare earth materials in the Western Hemisphere, operating the Mountain Pass mine in California. Rare earths are critical components in electric vehicle motors, wind turbines, electronics, and defense applications.',

  // Fintech
  'UPST': 'Upstart Holdings operates an AI-powered lending platform that partners with banks and credit unions to improve access to affordable credit. The company uses machine learning models that go beyond traditional credit scores to assess borrower risk.',
  'LC': 'LendingClub is a digital marketplace bank that connects borrowers with investors through its online lending platform. The company offers personal loans, auto refinancing, and patient financing while operating as a full-service digital bank.',

  // Diagnostics / Life Sciences
  'EXAS': 'Exact Sciences develops and markets cancer screening and diagnostic tests, best known for Cologuard, a non-invasive colorectal cancer screening test. The company also offers Oncotype DX for breast cancer prognosis and is expanding into multi-cancer early detection.',

  // Quantum Computing
  'IONQ': 'IonQ is a quantum computing company building general-purpose trapped-ion quantum computers available through major cloud platforms. The company aims to make quantum computing commercially viable for applications in chemistry, finance, logistics, and machine learning.',
  'RGTI': 'Rigetti Computing designs and manufactures superconducting quantum computers and provides cloud access to its quantum processors. The company focuses on hybrid classical-quantum computing for near-term practical applications.',

  // AI Pure-play
  'SOUN': 'SoundHound AI develops voice AI technology and conversational intelligence platforms used in automotive, restaurant, and IoT applications. The company\'s AI assistants enable voice-enabled ordering, customer service, and device interactions for enterprise customers.',
  'BBAI': 'BigBear.ai provides AI-powered analytics and cyber engineering solutions to defense, intelligence, and commercial customers. The company specializes in predictive analytics, autonomous systems, and decision support for complex operational environments.',

}

export function getCompanyDescription(symbol: string): string | null {
  return DESCRIPTIONS[symbol] || null
}
